      assert.ok(await exists(target), "original target must be restored");
      assert.ok(
        await exists(path.join(target, "SKILL.md")),
        "original content must be present",
      );
    } finally {
      try {
        await chmod(
          path.join(home, ".inception-engine", "registry.json"),
          0o666,
        );
